class Model(torch.nn.Module):
    def __init__(self, split_sizes, add_value):
        super().__init__()
        self.split_sizes = split_sizes
        self.add_value = add_value

    def forward(self, x):
        split_outputs = torch.split_with_sizes(x, self.split_sizes)
        added_outputs = [torch.add(output, self.add_value) for output in split_outputs]
        return torch.cat(added_outputs, dim=0)


