import torch


class Model(torch.nn.Module):
    def __init__(self, input_size, split_sizes, num_splits):
        super().__init__()
        self.input_size = input_size
        self.split_sizes = split_sizes
        self.num_splits = num_splits

    def forward(self, x):
        # Split the tensor along dimensions
        split_tensors = torch.split_with_sizes(x, self.split_sizes, dim=self.input_size)
        # Multiply each split tensor by a scalar (constant value 2.0 in this case)
        mul_tensors = [torch.mul(t, 2.0) for t in split_tensors]
        # Concatenate all tensors along the specified dimension
        return torch.cat(mul_tensors, dim=self.input_size)


