class Model(nn.Module):
    def __init__(self):
        super().__init__()
        self.relu = nn.ReLU()

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # Assuming we want to split x into two equally sized parts
        size_per_split = x.shape[2] // 2
        splits = torch.split_with_sizes(x, [size_per_split, size_per_split], dim=2)
        # Apply ReLU to each split
        relu_splits = [self.relu(split) for split in splits]
        # Concatenate the results along the channel dimension
        return torch.cat(relu_splits, dim=2)


