class Model(nn.Module):
    def __init__(self, module_dict_keys, diag_sizes):
        super().__init__()
        self.module_dict = nn.ModuleDict({key: nn.Module() for key in module_dict_keys})
        self.diag_sizes = diag_sizes

    def forward(self, x):
        for key, module in self.module_dict.items():
            x = torch.diag(x, diagonal=self.diag_sizes[key])
        return x


