class Model(torch.nn.Module):
    def __init__(self):
        super(Model, self).__init__()

    def forward(self, x):
        mask = torch.tril(torch.ones_like(x))  # create a lower triangular mask
        mask = torch.where(torch.lt(x, 0), torch.zeros_like(x), mask)  # replace elements below 0 with 0
        return x * mask


