class Model(nn.Module):
    def __init__(self, comparing_value, modules_dict_size):
        super().__init__()
        self.comparing_value = comparing_value
        self.modules_dict = nn.ModuleDict({f"module_{i}": nn.Identity() for i in range(modules_dict_size)})

    def forward(self, x):
        equal_tensors = torch.eq(x, self.comparing_value)
        for key, module in self.modules_dict.items():
            x = module(x) if equal_tensors.any() else x
        return x


