class Model(torch.nn.Module):
    def __init__(self, mask_value, grid_shape, mask_shape):
        super().__init__()
        self.mask_value = mask_value
        self.grid_shape = grid_shape
        self.mask_shape = mask_shape

    def forward(self, x):
        grid_x, grid_y = torch.meshgrid(
            torch.linspace(-1, 1, self.grid_shape[1]), torch.linspace(-1, 1, self.grid_shape[0])
        )
        mask = (grid_x - 0.5) ** 2 + (grid_y - 0.5) ** 2 > 0.2**2
        mask = mask.expand(self.mask_shape).to(x.device)
        return torch.masked_fill(x, mask, self.mask_value)


