from torch import nn


class Model(nn.Module):
    def __init__(self, input_modules, shift):
        super().__init__()
        # Create a ModuleDict with the input modules
        self.module_dict = nn.ModuleDict(input_modules)
        # store shift for forward method
        self.shift = shift

    def forward(self, x):
        # Use roll operation on each module in the ModuleDict
        for module in self.module_dict.values():
            x = torch.roll(x, shifts=self.shift, dims=(1, 2))
        return x


