class Model(torch.nn.Module):
    def __init__(self, dim, k):
        super().__init__()
        self.dim = dim
        self.k = k

    def forward(self, x):
        top_values, top_indices = torch.topk(x, k=self.k, dim=self.dim)
        gathered = torch.gather(top_indices, dim=0, index=top_indices)
        return gathered


